const tfootSections = document.querySelectorAll('table.shop_table tfoot');

// Find the correct <tfoot> (one without "Actions:" row)
let targetTfoot = null;

Array.from(tfootSections).forEach((tfoot, index) => {
  const hasActions = Array.from(tfoot.querySelectorAll('tr > th')).some(th => 
    th.textContent.trim() === 'Actions:'
  );
  if (!hasActions) {
    targetTfoot = tfoot;
  }
});

// Process the target <tfoot>
let result;
let totalIndex;
if (targetTfoot) {
  const tfootElements = targetTfoot.querySelectorAll('tr');
  Array.from(tfootElements).forEach((tr, index) => {
    const th = tr.querySelector('th');
    if (th) {
      const thText = th.textContent.trim();
      if (thText.includes('Total')) {
        totalIndex = index;
      }
    }
  });
}
  return totalIndex + 1

